def place_bid():
    item_id = request.form.get('item_id')
    user_id = request.form.get('user_id')
    bid_amount = request.form.get('bid_amount')

    if not item_id or not user_id or not bid_amount:
        flash('Missing bid information')
        return redirect(url_for('index'))

    items = load_items()
    bids = load_bids()
    users = load_users()

    item = next((i for i in items if i['id'] == item_id), None)
    user = next((u for u in users if u['id'] == user_id), None)

    if item is None:
        flash('Item not found')
        return redirect(url_for('index'))
    if user is None:
        flash('User not found')
        return redirect(url_for('index'))

    try:
        bid_amount = float(bid_amount)
    except ValueError:
        flash('Invalid bid amount')
        return redirect(url_for('item_detail', item_id=item_id))

    highest_bid = max([float(b['amount']) for b in bids if b['item_id'] == item_id], default=item['start_bid'])

    if bid_amount <= highest_bid:
        flash(f'Bid must be higher than current highest bid: {highest_bid}')
        return redirect(url_for('item_detail', item_id=item_id))

    # For simplicity, bids are appended to bids.txt with status pending
    new_bid_id = str(len(bids) + 1)
    new_bid_entry = f"{new_bid_id}|{item_id}|{user_id}|{bid_amount}|TODO_TIME|pending\n"

    with open(BIDS_FILE, 'a', encoding='utf-8') as f:
        f.write(new_bid_entry)

    flash('Bid placed successfully!')
    return redirect(url_for('item_detail', item_id=item_id))


if __name__ == '__main__':
    app.run(debug=True)

